-- Run this in Supabase SQL Editor to replace Fleet & Equipment with the PDF asset master.
alter table assets
  add column if not exists general_type text,
  add column if not exists old_qr_code text,
  add column if not exists last_update_date date,
  add column if not exists qr_printed_tagged text;
begin;
update work_orders set asset_id = null where asset_id is not null;
update rentals set item_id = null where item_type = 'Asset';
delete from assets;
delete from asset_locations;
delete from asset_types;
commit;
